THE CLAIM:
{
 "title": "CE-7 share is based on old racks, but new sales chase new builds",
 "narrative": "The model splits Europe's colocation market by standing capacity, giving CE-7 a 39.8% share. But rack-PDU revenue is earned when new capacity is built or refreshed, and 57% of 2025's 937MW of new supply lands in FLAPD, outside most of CE-7. That means the €300M overstates where 2026 PDU orders will actually be written.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "New builds drive sales: 57% of 937MW lands in FLAPD",
   "refs": [
    "digest:geo-region-denominator#c6",
    "digest:geo-region-denominator#c7",
    "digest:geo-region-denominator#c9"
   ]
  },
  {
   "step": "propagation",
   "text": "Growth goes to London, Milan and Madrid, not CE-7",
   "refs": [
    "digest:geo-region-denominator#c3",
    "digest:geo-region-denominator#c8",
    "digest:geo-region-denominator#c19"
   ]
  },
  {
   "step": "model-impact",
   "text": "The 39.8% share overstates near-term PDU revenue for CE-7",
   "refs": [
    "ledger:tamBase",
    "digest:geo-region-denominator#c4"
   ]
  }
 ],
 "falsifier": "CBRE's 2025–26 pipeline showing CE-7 capturing 38% or more of new European colocation MW delivered.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "New Investment in Europe's Data Centre Markets to Hit New Heights in 2025",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025-02-13",
   "excerpt": "More than half (57%) of this capacity is expected to be delivered in the leading European data centre markets - Frankfurt, London, Amsterdam, Paris and Dublin.",
   "url": "https://www.cbre.co.uk/press-releases/europes-data-centre-markets-to-hit-new-heights",
   "attached": true
  },
  {
   "title": "European Real Estate Market Outlook Mid-Year Review 2025 — Data Centres",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025",
   "excerpt": "London and Frankfurt are expected to account for 2.5GW of capacity, or approximately half of the total data centre supply in Europe, by the end of 2025. Most new supply in Europe (70%) will be delivered to the five largest markets – FLAPD.",
   "url": "https://www.cbre.com/insights/books/european-real-estate-market-outlook-mid-year-review-2025/data-centres",
   "attached": true
  },
  {
   "title": "Data Centre Take-up in Europe to Reach New Peak in 2025",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025-05-27",
   "excerpt": "Almost half (46%) of the annual take-up this year is expected to be in London and Frankfurt, the two largest colocation data centre markets of Europe.",
   "url": "https://www.cbre.co.uk/press-releases/data-centre-take-up-in-europe-to-reach-new-peak-in-2025",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 300,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 360
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €300M",
   "crossCheck": "Refinement cycle 1: the prior €495M ceiling (BIS/R&M €2.45B) measures PDUs+PSUs combined — a broader category growing 21% CAGR vs intelligent-PDU 10–12% (IndexBox). Contaminated ceiling removed; band top lowered to €360M."
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; the scope-down chain anchors the value, and refinement cycle 1 killed the inflated PDUs+PSUs cross-check ceiling.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
